```javascript
const readlineSync = require('readline-sync');

function encryptString(inputString) {
 const words = inputString.split(' ').reverse();
 let encryptedString = '';

 for (let i = 0; i < words.length; i++) {
    const word = words[i];
    const reversedWord = word.split('').reverse().join('');

    for (let j = 0; j < reversedWord.length - 1; j++) {
      encryptedString += reversedWord[j] + reversedWord[0];
    }

    encryptedString += reversedWord[reversedWord.length - 1];

    if (i < words.length - 1) {
      encryptedString += ' ';
    }
  }

  return encryptedString;
}

const inputString = readlineSync.question('Please enter a string of text (max 20 words): ');

if (inputString.split(' ').length > 20) {
 console.log('Error: The input string contains more than 20 words.');
 process.exit(1);
}

const encryptedString = encryptString(inputString);
console.log(`Encrypted string: ${encryptedString}`);
